# Base module providing student-related classes and utilities

class Person:
    name: str
    age: int

    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age

    @virtual def get_description(self) -> str:
        return f"Person: {self.name}"

class Student(Person):
    student_id: int
    grades: list[int]

    def __init__(self, name: str, age: int, student_id: int):
        super().__init__(name, age)
        self.student_id = student_id
        self.grades = []

    def add_grade(self, grade: int) -> None:
        self.grades.append(grade)

    @override def get_description(self) -> str:
        return f"Student {self.student_id}: {self.name}"

def calculate_average(scores: list[int]) -> float:
    if len(scores) == 0:
        return 0.0
    total: int = sum(scores)
    return float(total) / float(len(scores))

def format_score(score: float) -> str:
    return f"{score:.1f}"

