# Utility module for grading operations
from student_base import Student, calculate_average

def calculate_class_average(students: list[Student]) -> float:
    all_grades: list[int] = []
    for s in students:
        for g in s.grades:
            all_grades.append(g)
    return calculate_average(all_grades)

def get_top_student(students: list[Student]) -> Student:
    best: Student = students[0]
    best_avg: float = calculate_average(best.grades)
    for s in students[1:]:
        s_avg: float = calculate_average(s.grades)
        if s_avg > best_avg:
            best = s
            best_avg = s_avg
    return best

interface IReportable:
    def generate_report(self) -> str

class GradeReport:
    title: str
    entries: list[str]

    def __init__(self, title: str):
        self.title = title
        self.entries = []

    def add_entry(self, text: str) -> None:
        self.entries.append(text)

    def get_summary(self) -> str:
        return f"{self.title} - {len(self.entries)} entries"
